import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

import java.util.Scanner;

public class SecureXSSExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize and escape user input using ESAPI to prevent XSS
        HTMLEntityCodec htmlCodec = new HTMLEntityCodec();
        String safeInput = htmlCodec.encodeForHTML(userInput);

        System.out.println("<div>Welcome, " + safeInput + "!</div>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
